#include<bits/stdc++.h>
using namespace std;
int n, m;
bool a[10001][10001];
int in[10001];
int out[10001];
int f[10001];
int main() {
	cin >> n >> m;
	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		a[x][y] = 1;
		in[y]++;
		out[x]++;
	}
	for (int i = 1; i <= n; i++) {
		if (in[i] == 0) {
			f[i] = 1;
		}
	}
	queue<int> q;
	for (int i = 1; i <= n; i++) {
		if (in[i] == 0) {
			q.push(i);
		}
	}
	while (!q.empty()) {
		int x = q.front();
		q.pop();
		for (int i = 1; i <= n; i++) {
			if (a[x][i]) {
				f[i] = (f[i] + f[x]) %  80112002 ;
				a[x][i] = 0;
				in[i]--;
				if (in[i] == 0) {
					q.push(i);
				}
				//out[x]--;
			}
		}
	}
	int ans = 0;
	for (int i = 1; i <= n; i++) {
		if (out[i] == 0) {
			ans = (ans + f[i]) % 80112002;
		}
	}
	cout << ans;
	return 0;
}
